html:xslt.xsl:template:
function Detail(poiTarea) {
	var dir;

	dir = "../../../ReportViewer.aspx?";
	dir = dir + "report={#PROXY.APP#}.NucleusProject.Base.Project.Tarea.GEN.GADGET";
	dir = dir + "{#CHAR.AMP#}oi_tarea=" + poiTarea;

	window.open(dir, 'Buscador', 'width=500,height=350,resizable=yes');
}
